const body = $input.first().json.body;
if (!body) throw new Error('Missing request body');
return [{ json: { data: JSON.stringify(body) } }];

const result = $input.first().json;
const stdout = result.stdout || '';
const stderr = result.stderr || '';

if (stderr) console.error('Script stderr:', stderr);

let orderNumber = '';
let pdfPath = '';

try {
  const parsed = JSON.parse(stdout);
  orderNumber = parsed.orderNumber || '';
  pdfPath = parsed.pdfPath || '';
} catch {
  const orderMatch = stdout.match(/orderNumber[=:]\s*(\S+)/);
  if (orderMatch) orderNumber = orderMatch[1];
  const pdfMatch = stdout.match(/pdfPath[=:]\s*(\S+)/);
  if (pdfMatch) pdfPath = pdfMatch[1];
}

return [{ json: { orderNumber, pdfPath, raw: stdout } }];
